import dspy

class StateConsistencyChecker:
    def __init__(self):
        self.last_agent_output = None

    def check(self, module: dspy.Module, example: dspy.Example, state_key: str = 'shared_state') -> bool:
        output = module.forward(example)
        current_state = output.get(state_key)

        if self.last_agent_output:
            # Check if current agent references previous state
            if state_key not in output or current_state != self.last_agent_output:
                print(f'State inconsistency: expected {self.last_agent_output}, got {current_state}')
                return True

        self.last_agent_output = current_state
        return False

