import dspy
from difflib import SequenceMatcher

def detect_overlap(agent_outputs: list[str], threshold: float = 0.8) -> bool:
    """Detects excessive overlap between parallel agent outputs"""
    for i, out1 in enumerate(agent_outputs):
        for out2 in agent_outputs[i+1:]:
            similarity = SequenceMatcher(None, out1, out2).ratio()
            if similarity > threshold:
                print(f'High overlap ({similarity:.2f}) between agents')
                return True
    return False

# Usage in DSPy module
class ParallelAgents(dspy.Module):
    def forward(self, example):
        outputs = [agent(example) for agent in self.agents]
        if detect_overlap([o.output for o in outputs]):
            raise ValueError('Agent coordination failure: excessive overlap')
        return dspy.Prediction(output=str(outputs))

