import dspy

class CoordinatedAgentSignature(dspy.Signature):
    """Shared state format for multi-agent coordination"""
    shared_state = dspy.InputField(desc="JSON string of previous agent outputs")
    agent_id = dspy.InputField(desc="Unique agent identifier")
    task = dspy.InputField()
    output = dspy.OutputField(desc="JSON: {'result': str, 'references_prev': bool, 'state_update': dict}")

class StateAwareAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(CoordinatedAgentSignature)

    def forward(self, example):
        state_str = example.get('shared_state', '{}')
        pred = self.generate(task=example.task, shared_state=state_str, agent_id=self.agent_id)
        return dspy.Prediction(output=pred.output, state_update=pred.output)

import dspy
import json

class OutputNormalizer(dspy.Module):
    def __init__(self, schema: dict):
        super().__init__()
        self.schema = schema

    def forward(self, example):
        raw_output = example.output
        normalized = self._normalize(raw_output)
        return dspy.Prediction(
            output=json.dumps(normalized),
            raw_output=raw_output
        )

    def _normalize(self, output: str) -> dict:
        try:
            parsed = json.loads(output)
            return {k: parsed.get(k, self.schema[k]['default']) for k in self.schema}
        except:
            return {k: self.schema[k]['default'] for k in self.schema}

# Usage
normalizer = OutputNormalizer({
    'agent_id': {'default': 'unknown'},
    'result': {'default': ''},
    'confidence': {'default': 0.0}
})

